-- 1. Se agregan configuraciones parametrizables para checkout, pago, soporte y comprobante del módulo TIENDA_PUBLICA.
  INSERT INTO system.modulo_configuraciones
  (
    modulo_id,
    codigo,
    nombre,
    descripcion,
    tipo_dato,
    valor_defecto,
    valor,
    accion,
    orden,
    estado,
    borrado,
    usuario_creacion,
    fecha_creacion,
    usuario_modificacion,
    fecha_modificacion,
    usuario_borrado,
    fecha_borrado
  )
  SELECT
    sys_mod.modulo_id,
    v.codigo,
    v.nombre,
    v.descripcion,
    v.tipo_dato,
    v.valor_defecto,
    v.valor,
    v.accion,
    v.orden,
    B'1',
